/* Aula 04 — modelJs: Strings e Números */

// 1) Limpar e transformar nome
const nomeSujo = '  bruno carvalho  ';
const nomeLimpo = nomeSujo.trim();
const nomeMaiusculo = nomeLimpo.toUpperCase();
console.log('nomeLimpo:', nomeLimpo);
console.log('nomeMaiusculo:', nomeMaiusculo);

// 2) Verificar email
const email = 'bruno@gmail.com';
console.log('tem @ ?', email.includes('@'));

// 3) Converter e somar
const n1 = '10';
const n2 = '25';
console.log('soma:', Number(n1) + Number(n2)); // 35

// 4) Formatar preço
const preco = 19.9;
console.log(`R$ ${preco.toFixed(2)}`); // 'R$ 19.90'

// 5) Pegadinha
console.log('10' + 5);          // '105'
console.log(Number('10') + 5);  // 15
